UPDATE engineering_articles SET body_html = REPLACE(body_html,
  '<h3>3.4. ТВЧ-закалка</h3><p>Поверхностная закалка током высокой частоты с глубиной слоя 1,0…6,0 мм. Применяется для валов, шеек коленчатых валов, зубьев крупномодульных колёс. Твёрдость HRC 50…55 при сохранении вязкой сердцевины. Базовые марки: сталь 45, 40Х, 50Х [5, с. 138].</p>',
  '<h3>3.4. ТВЧ-закалка</h3><p>Поверхностная закалка током высокой частоты с глубиной слоя 1,0…6,0 мм. Применяется для валов, шеек коленчатых валов, зубьев крупномодульных колёс. Твёрдость HRC 50…55 при сохранении вязкой сердцевины. Базовые марки: сталь 45, 40Х, 50Х [5, с. 138]. Классическая монография К. З. Шепеляковского [11] остаётся ключевым российским источником по индукционному поверхностному упрочнению: от выбора частоты тока до режимов закалки шеек коленвалов и зубьев крупномодульных колёс. По химико-термической обработке зубчатых колёс — специализированная работа В. М. Зинченко [8] от МГТУ им. Баумана.</p>'
)
WHERE slug = 'vybor-stali-i-termoobrabotki-dlya-detaley-mashin';